type AgentCommand =
  | { type: 'send_user_turn'; sessionId: string; text: string }
  | { type: 'interrupt_agent'; sessionId: string }
  | { type: 'approve_tool_action'; sessionId: string; approvalId: string }
  | { type: 'add_context'; sessionId: string; text: string };

type AgentEvent =
  | { type: 'agent.started'; sessionId: string }
  | { type: 'agent.text_delta'; sessionId: string; text: string }
  | { type: 'agent.tool_running'; sessionId: string; tool: string }
  | { type: 'agent.awaiting_approval'; sessionId: string; approvalId: string; label: string }
  | { type: 'agent.completed'; sessionId: string }
  | { type: 'agent.error'; sessionId: string; message: string };
